import{c as a,S as e,j as i,m as t}from"./chunks/framework.DvQr6YbT.js";const k=JSON.parse('{"title":"订阅与更新","description":"","frontmatter":{},"headers":[],"relativePath":"zh/sharing/subscribe-update.md","filePath":"zh/sharing/subscribe-update.md","lastUpdated":1783418049000}'),n={name:"zh/sharing/subscribe-update.md"};function l(d,s,r,h,p,o){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="订阅与更新" tabindex="-1">订阅与更新 <a class="header-anchor" href="#订阅与更新" aria-label="Permalink to “订阅与更新”">​</a></h1><p>从 GitHub Release 链接安装知识包的那一刻，你就成了订阅者：vault 记住了它的来源， 并且可以向那个来源询问新版本。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check-updates</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>jay.drone-delivery  v1.2.0 → v1.3.0 available</span></span>
<span class="line"><span>team.obs-pack       v2.0.0 — up to date</span></span>
<span class="line"><span>old.zip-install     v1.0.0 — unchecked (no version protocol for this source)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1 update(s) available — install with: knowlery bundle update &lt;id&gt; (or --all)</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jay.drone-delivery</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 或 --all</span></span></code></pre></div><p>更新走<strong>完整的安装管道</strong>——规范门、版本门、路径安全——并且替换是分阶段的： 任何环节失败，已安装版本原封不动。</p><p>在 Obsidian 里，dashboard 的 <em>Installed bundles</em> 区块有 <strong>Check updates</strong> 按钮 和逐包的 Update 按钮。</p><h2 id="订阅模型" tabindex="-1">订阅模型 <a class="header-anchor" href="#订阅模型" aria-label="Permalink to “订阅模型”">​</a></h2><ul><li><strong>只拉不推。</strong>没有任何后台检查；由你（或你的 agent，按你们约定的节奏）主动 运行检查。<code>knowlery sync</code> 刻意保持离线——<code>check-updates</code> 是它的网络侧姊妹命令。</li><li><strong>权限即成员身份。</strong>更新来自你当初安装的同一来源、同样的访问规则——组织成员 只要还在组织里就能持续收到更新。参见<a href="./grant-access">授权</a>。</li><li><strong>状态分类是诚实的</strong>：<code>unchecked</code> 表示该来源没有版本发现协议（裸 zip 链接）； <code>skipped</code> 表示私有来源需要 <code>gh</code>；两者都不是错误。</li></ul><h2 id="本地修改受保护" tabindex="-1">本地修改受保护 <a class="header-anchor" href="#本地修改受保护" aria-label="Permalink to “本地修改受保护”">​</a></h2><p>如果你编辑过 <code>Library/&lt;bundle-id&gt;/</code> 里的文件，更新会覆盖你的改动——所以它会拒绝, 并精确列出哪些文件被编辑、新增或删除。惯例是：<strong>装进来的知识用于引用,不用于 编辑</strong>——把你自己的见解写在自己的页面里,链接到知识包的页面。确定要覆盖时用 <code>--force</code>。</p><h2 id="版本说明" tabindex="-1">版本说明 <a class="header-anchor" href="#版本说明" aria-label="Permalink to “版本说明”">​</a></h2><p>知识包版本是稳定的数字点分格式（<code>1.2.0</code>、<code>1.10.0</code>——按数字比较,所以 <code>1.10 &gt; 1.9</code>）。没有降级命令：要回滚,直接重新安装旧版本 Release 的链接。</p>`,13)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
